CREATE TYPE "ApprovalStatus" AS ENUM ('DRAFT','PENDING','APPROVED','REJECTED');
CREATE TABLE "Survey"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"projectId" UUID NOT NULL,"requestedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"scheduledAt" TIMESTAMP(3),"surveyedAt" TIMESTAMP(3),"location" TEXT,"siteCondition" TEXT,"measurements" JSONB,"notes" TEXT,"approvalStatus" "ApprovalStatus" NOT NULL DEFAULT 'DRAFT',"version" INTEGER NOT NULL DEFAULT 1,"createdBy" UUID NOT NULL,"updatedBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"deletedAt" TIMESTAMP(3),CONSTRAINT "Survey_pkey" PRIMARY KEY("id"));
CREATE TABLE "Requirement"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"projectId" UUID NOT NULL,"surveyId" UUID,"title" TEXT NOT NULL,"customerRequirements" TEXT,"stylePreferences" TEXT,"brandPreferences" TEXT,"budgetMin" DECIMAL(20,2),"budgetMax" DECIMAL(20,2),"currency" TEXT NOT NULL DEFAULT 'VND',"expectedSchedule" TEXT,"status" TEXT NOT NULL DEFAULT 'DRAFT',"approvalStatus" "ApprovalStatus" NOT NULL DEFAULT 'DRAFT',"version" INTEGER NOT NULL DEFAULT 1,"createdBy" UUID NOT NULL,"updatedBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"deletedAt" TIMESTAMP(3),CONSTRAINT "Requirement_pkey" PRIMARY KEY("id"));
CREATE TABLE "RequirementVersion"("id" UUID NOT NULL,"requirementId" UUID NOT NULL,"version" INTEGER NOT NULL,"snapshot" JSONB NOT NULL,"createdBy" UUID NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "RequirementVersion_pkey" PRIMARY KEY("id"));
CREATE INDEX "Survey_organizationId_projectId_approvalStatus_deletedAt_idx" ON "Survey"("organizationId","projectId","approvalStatus","deletedAt");CREATE INDEX "Requirement_organizationId_projectId_approvalStatus_deleted_idx" ON "Requirement"("organizationId","projectId","approvalStatus","deletedAt");CREATE UNIQUE INDEX "RequirementVersion_requirementId_version_key" ON "RequirementVersion"("requirementId","version");
ALTER TABLE "Survey" ADD CONSTRAINT "Survey_organizationId_fkey" FOREIGN KEY("organizationId") REFERENCES "Organization"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Survey" ADD CONSTRAINT "Survey_projectId_fkey" FOREIGN KEY("projectId") REFERENCES "Project"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Requirement" ADD CONSTRAINT "Requirement_organizationId_fkey" FOREIGN KEY("organizationId") REFERENCES "Organization"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Requirement" ADD CONSTRAINT "Requirement_projectId_fkey" FOREIGN KEY("projectId") REFERENCES "Project"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Requirement" ADD CONSTRAINT "Requirement_surveyId_fkey" FOREIGN KEY("surveyId") REFERENCES "Survey"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "RequirementVersion" ADD CONSTRAINT "RequirementVersion_requirementId_fkey" FOREIGN KEY("requirementId") REFERENCES "Requirement"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
